//! # Real Spectral Manifest Construction (Phase 2 ASAP)
//!
//! Derives a [`SpectralManifest`] from per-column L2 magnitude statistics
//! across the Q/K/V dense weight matrices, instead of running a live
//! attention probe. This is a defensible proxy: high-magnitude columns
//! ARE the resonant dimensions in the trained network's basis. Phase 3
//! will swap this for a live attention tap.
//!
//! Mirrors the data flow `manifest_from_patterns` will eventually
//! provide; for now we pull the standing dimensions directly from the
//! weight tensors that the dense `.knot` already exposes.

use super::format::*;

/// Compute per-column L2 magnitudes for a row-major dense tensor.
///
/// Walks every `(row, col)` pair, accumulates `tensor.get(row, col)²`
/// per column, then takes the square root. Returns a vector of length
/// `tensor.cols`.
///
/// Bounds-checked via [`DenseTensor::get`] so out-of-range indices
/// contribute 0.0 rather than panicking — matches Lean
/// `tensor_get`'s `getD 0.0` semantics.
pub fn column_magnitudes(tensor: &DenseTensor) -> Vec<f32> {
    let cols = tensor.cols as usize;
    let mut sums = vec![0.0_f32; cols];
    for row in 0..tensor.rows {
        for col in 0..tensor.cols {
            let v = tensor.get(row, col);
            sums[col as usize] += v * v;
        }
    }
    for s in sums.iter_mut() {
        *s = s.sqrt();
    }
    sums
}

/// Compute per-column maximum absolute element magnitude for a
/// row-major dense tensor: `out[c] = max_r |tensor.get(r, c)|`.
///
/// Returns a vector of length `tensor.cols`. Used as a tie-breaker
/// alongside L2 column magnitudes so that columns containing extreme
/// outlier elements are not evicted from the standing manifest. See the
/// `outlier_preservation_*` tests and the cloud-probe `e839d9dd`
/// motivation in `manifest_from_weight_magnitudes`.
///
/// NaN/Inf values are skipped (treated as 0) so a single bad weight
/// can't poison the column score.
pub fn column_abs_max(tensor: &DenseTensor) -> Vec<f32> {
    let cols = tensor.cols as usize;
    let mut out = vec![0.0_f32; cols];
    for row in 0..tensor.rows {
        for col in 0..tensor.cols {
            let v = tensor.get(row, col);
            if v.is_finite() {
                let a = v.abs();
                let slot = &mut out[col as usize];
                if a > *slot {
                    *slot = a;
                }
            }
        }
    }
    out
}

/// Fraction of the standing budget reserved for absolute-magnitude
/// outlier preservation. The encoder computes its primary score
/// (combined column-L2 magnitude on Q/K/V, or PCA coordinate score on
/// the calibrated path) and selects the top
/// `K - round(K * OUTLIER_RESERVE_FRACTION)` indices by score. The
/// remainder is filled by the top columns ordered by `column_abs_max`,
/// so any column that contains an extreme weight value (the
/// ±70 / ±90 outliers that surfaced in cloud probe `e839d9dd` on L0
/// attn_q / ffn_gate) survives manifest construction even when its
/// column-L2 score would have been beaten by denser-but-smaller peers.
///
/// Conservative default of `0.25` (one-quarter of the budget) — keeps
/// the bulk of the score-driven selection intact while guaranteeing
/// outliers are represented. If post-fix probes show outliers still
/// being evicted, raise toward `0.5`; if cosine to dense regresses,
/// lower toward `0.10`.
pub const OUTLIER_RESERVE_FRACTION: f32 = 0.25;

/// Select `k` standing indices into `[0, d)` using a score-driven
/// primary pass with an outlier-preservation reserve.
///
/// Procedure:
/// 1. Compute `reserve = round(k × OUTLIER_RESERVE_FRACTION)`,
///    `primary_k = k - reserve`.
/// 2. Pick the top `primary_k` indices by `score` (descending).
/// 3. Walk indices ordered by `abs_max` descending and add up to
///    `reserve` indices that are not already in the primary set. This
///    is the "outlier guard": columns containing an extreme element
///    survive even when their `score` would have evicted them.
/// 4. If the union still has fewer than `k` entries (small `d`,
///    massive overlap between the two orderings), backfill from the
///    score order until the manifest is full.
/// 5. Return the union sorted ascending — matches the manifest
///    invariant required by the writer/reader offset tables.
///
/// The two input vectors must be `d`-long. Ties on `score` break by
/// ascending index for cross-platform determinism; ties on `abs_max`
/// likewise. NaN values rank lowest in both orderings.
pub fn select_with_outlier_reserve(d: u32, k: u32, score: &[f32], abs_max: &[f32]) -> Vec<u32> {
    debug_assert_eq!(score.len(), d as usize);
    debug_assert_eq!(abs_max.len(), d as usize);
    let k = k.min(d) as usize;
    if k == 0 {
        return Vec::new();
    }

    // Reserve a fraction of the budget for absolute-magnitude outliers.
    // Round to nearest, but never starve the primary score-driven pass
    // when k is tiny: cap the reserve at `k - 1` so the score still
    // gets at least one slot whenever k >= 1, and the outlier reserve
    // gets at least one slot whenever k >= 2.
    let reserve_raw = (k as f32 * OUTLIER_RESERVE_FRACTION).round() as usize;
    let reserve = reserve_raw.min(k.saturating_sub(1));
    let primary_k = k - reserve;

    // Helper closure: cmp pair `(metric desc, index asc)`.
    let mut by_score: Vec<u32> = (0..d).collect();
    by_score.sort_by(|a, b| {
        let ma = score[*a as usize];
        let mb = score[*b as usize];
        mb.partial_cmp(&ma)
            .unwrap_or(std::cmp::Ordering::Equal)
            .then_with(|| a.cmp(b))
    });

    let mut selected = vec![false; d as usize];
    let mut out: Vec<u32> = Vec::with_capacity(k);
    for &idx in by_score.iter().take(primary_k) {
        if !selected[idx as usize] {
            selected[idx as usize] = true;
            out.push(idx);
        }
    }

    if reserve > 0 {
        let mut by_abs: Vec<u32> = (0..d).collect();
        by_abs.sort_by(|a, b| {
            let ma = abs_max[*a as usize];
            let mb = abs_max[*b as usize];
            mb.partial_cmp(&ma)
                .unwrap_or(std::cmp::Ordering::Equal)
                .then_with(|| a.cmp(b))
        });
        let mut added = 0usize;
        for &idx in &by_abs {
            if added >= reserve {
                break;
            }
            if !selected[idx as usize] {
                selected[idx as usize] = true;
                out.push(idx);
                added += 1;
            }
        }
    }

    // Backfill from the score order for the rare case where the
    // outlier reserve couldn't be filled (e.g. d < k). This guarantees
    // the manifest carries exactly `k` indices whenever `k <= d`.
    if out.len() < k {
        for &idx in &by_score {
            if out.len() >= k {
                break;
            }
            if !selected[idx as usize] {
                selected[idx as usize] = true;
                out.push(idx);
            }
        }
    }

    out.sort_unstable();
    out
}

/// Derive a [`SpectralManifest`] by selecting the top
/// `k = round(d × coverage)` columns by combined Q/K/V L2 magnitude.
///
/// **Axis convention:** `d` is taken from `q.cols` (the Q **column** count,
/// i.e. one index per hidden channel in Q's output layout). Per-column L2
/// norms are accumulated independently for Q, K, and V via
/// [`column_magnitudes`].
///
/// **GQA / rectangular K,V:** after `dense_reader::load_layer_blocks`,
/// K and V are `[hidden, kv_dim]` with `kv_dim < d` (e.g. Llama-70B:
/// `kv_dim = num_kv_heads × head_dim`). Then `column_magnitudes(k)` has
/// length `kv_dim`. For combined score at column index `c`, K and V only
/// contribute when `c < kv_dim`; for `c ≥ kv_dim` the score uses **Q
/// alone**. This is a deliberate magnitude heuristic (Phase 2), not a
/// full head-mapping from KV space into Q's concatenated head layout.
/// Phase 3 live-attention manifests may supersede this.
///
/// Indices are returned sorted ascending — the manifest contract
/// requires this so the writer/reader can use offset-tables without
/// re-sorting on the read side.
///
/// `amplitudes` are the (normalized) combined magnitudes at each
/// standing index. `phase_alignment` defaults to `0.7` until the real
/// attention probe lands in Phase 3.
///
/// `coverage` is clamped to `[0.0, 1.0]`. The integer-math `k`
/// derivation matches [`super::manifest::stub_first_k_manifest`] so
/// `coverage = 0.30, d = 100` yields `k = 30` (not `31` from the
/// `100.0 * 0.30 → 30.000001` float trap).
pub fn manifest_from_weight_magnitudes(
    q: &DenseTensor,
    k_t: &DenseTensor,
    v: &DenseTensor,
    coverage: f32,
) -> SpectralManifest {
    // d is taken from Q's column count — one score slot per Q column.
    // Narrower K/V matrices contribute only on the shared prefix of column
    // indices; see module-level docs on GQA.
    let d = q.cols;
    let coverage = coverage.clamp(0.0, 1.0);

    // Integer-math k derivation, mirroring stub_first_k_manifest, to
    // dodge the `coverage * d` float-precision trap.
    let k = ((d as u64 * (coverage * 1_000.0).round() as u64 + 500) / 1_000) as u32;
    let k = k.min(d);

    let mag_q = column_magnitudes(q);
    let mag_k = column_magnitudes(k_t);
    let mag_v = column_magnitudes(v);

    // Per-column abs-max across Q/K/V — feeds the outlier-preservation
    // pass below. Cloud probe `e839d9dd` (canonical.rknot, L0 fidelity)
    // showed attn_q max_err=72 and ffn_gate max_err=92 against ~6e-3
    // mean errors: a small handful of EXTREME-magnitude elements were
    // being dropped because their host columns had lower combined-L2
    // than denser-but-smaller peers. The abs-max pass forces those
    // columns into the manifest.
    let abs_q = column_abs_max(q);
    let abs_k = column_abs_max(k_t);
    let abs_v = column_abs_max(v);

    let d_usize = d as usize;
    let mut combined = vec![0.0_f32; d_usize];
    let mut abs_max = vec![0.0_f32; d_usize];
    for c in 0..d_usize {
        // 0-fill any column missing from K or V (they may be narrower
        // than Q in the GQA / kv-head case; column_magnitudes returns
        // exactly cols entries, so guard with `get`).
        let mq = *mag_q.get(c).unwrap_or(&0.0);
        let mk = *mag_k.get(c).unwrap_or(&0.0);
        let mv = *mag_v.get(c).unwrap_or(&0.0);
        combined[c] = mq + mk + mv;
        let aq = *abs_q.get(c).unwrap_or(&0.0);
        let ak = *abs_k.get(c).unwrap_or(&0.0);
        let av = *abs_v.get(c).unwrap_or(&0.0);
        abs_max[c] = aq.max(ak).max(av);
    }

    let standing_indices = select_with_outlier_reserve(d, k, &combined, &abs_max);

    // Normalize amplitudes so the largest standing dim has amplitude
    // 1.0 — keeps the encoder's bit-allocation invariant under
    // arbitrary tensor scale. If max is 0 (degenerate all-zero
    // tensors) we leave amplitudes at 0.0.
    let raw_amps: Vec<f32> = standing_indices
        .iter()
        .map(|&i| combined[i as usize])
        .collect();
    let max_amp = raw_amps.iter().cloned().fold(0.0_f32, f32::max);
    let amplitudes: Vec<f32> = if max_amp > 0.0 {
        raw_amps.iter().map(|a| a / max_amp).collect()
    } else {
        vec![0.0; raw_amps.len()]
    };

    let phase_alignment = vec![0.7; k as usize];

    SpectralManifest {
        d,
        k,
        standing_indices,
        amplitudes,
        phase_alignment,
    }
}

/// Compute the energy fraction captured by the standing dimensions of
/// the supplied manifest, restricted to `tensor`. Useful as a sanity
/// check ("did we actually pick the load-bearing dims?").
///
/// Returns a ratio in `[0, 1]`: the sum of squared values at columns
/// in `manifest.standing_indices` divided by the sum of squared
/// values across the whole tensor. Returns `0.0` if the denominator
/// is zero (all-zero tensor).
pub fn standing_energy_fraction(tensor: &DenseTensor, manifest: &SpectralManifest) -> f32 {
    let mut numerator = 0.0_f32;
    let mut denominator = 0.0_f32;

    // Pre-build a membership bitmap for O(1) "is this col standing?"
    // lookup. cols is bounded by the model's hidden dim (~16K), so
    // this is cheap.
    let cols = tensor.cols as usize;
    let mut in_manifest = vec![false; cols];
    for &i in &manifest.standing_indices {
        let idx = i as usize;
        if idx < cols {
            in_manifest[idx] = true;
        }
    }

    for row in 0..tensor.rows {
        for col in 0..tensor.cols {
            let v = tensor.get(row, col);
            let sq = v * v;
            denominator += sq;
            if in_manifest[col as usize] {
                numerator += sq;
            }
        }
    }

    if denominator == 0.0 {
        0.0
    } else {
        numerator / denominator
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    /// Helper: build a row-major DenseTensor from a `rows × cols`
    /// generator closure.
    fn build_tensor(rows: u32, cols: u32, mut f: impl FnMut(u32, u32) -> f32) -> DenseTensor {
        let mut data = Vec::with_capacity((rows * cols) as usize);
        for r in 0..rows {
            for c in 0..cols {
                data.push(f(r, c));
            }
        }
        DenseTensor { rows, cols, data }
    }

    #[test]
    fn column_magnitudes_returns_correct_length() {
        let t = build_tensor(7, 13, |_, _| 1.0);
        let mags = column_magnitudes(&t);
        assert_eq!(mags.len(), 13);
        // sqrt(7 * 1^2) = sqrt(7)
        for m in mags {
            assert!((m - (7.0_f32).sqrt()).abs() < 1e-5);
        }
    }

    #[test]
    fn magnitudes_pick_largest_for_unimodal_input() {
        // 100 × 100, only column 50 has any energy.
        let t = build_tensor(100, 100, |_, c| if c == 50 { 1.0 } else { 0.0 });
        // Pass the same tensor as Q/K/V — the only resonant column
        // is 50, so it MUST be in the selected set.
        let manifest = manifest_from_weight_magnitudes(&t, &t, &t, 0.05);
        // coverage 0.05 of d=100 → k=5 standing indices
        assert_eq!(manifest.d, 100);
        assert_eq!(manifest.k, 5);
        assert_eq!(manifest.standing_indices.len(), 5);
        assert!(
            manifest.standing_indices.contains(&50),
            "column 50 (the only non-zero) must be selected, got {:?}",
            manifest.standing_indices
        );
        // Indices must be sorted ascending per the manifest contract.
        for w in manifest.standing_indices.windows(2) {
            assert!(
                w[0] < w[1],
                "indices must be sorted: {:?}",
                manifest.standing_indices
            );
        }
        assert!(manifest.is_well_formed());
    }

    #[test]
    fn coverage_clamped() {
        let t = build_tensor(8, 16, |r, c| ((r + c) as f32) * 0.1);
        // coverage > 1 → clamps to 1.0 → k = d = 16
        let manifest = manifest_from_weight_magnitudes(&t, &t, &t, 1.7);
        assert_eq!(manifest.d, 16);
        assert_eq!(manifest.k, 16);
        assert_eq!(manifest.standing_indices.len(), 16);
        assert!(manifest.is_well_formed());

        // coverage < 0 → clamps to 0 → k = 0
        let manifest_zero = manifest_from_weight_magnitudes(&t, &t, &t, -0.5);
        assert_eq!(manifest_zero.k, 0);
        assert!(manifest_zero.is_well_formed());
    }

    #[test]
    fn energy_fraction_is_one_for_full_coverage() {
        // Mixed-magnitude tensor; full coverage manifest should
        // capture 100% of the energy.
        let t = build_tensor(20, 12, |r, c| ((r * 31 + c * 7 + 1) as f32).sin());
        let manifest = manifest_from_weight_magnitudes(&t, &t, &t, 1.0);
        assert_eq!(manifest.k, 12);
        let frac = standing_energy_fraction(&t, &manifest);
        assert!(
            (frac - 1.0).abs() < 1e-5,
            "full-coverage energy fraction should be 1.0, got {}",
            frac
        );
    }

    /// GQA: K/V have fewer columns than Q. Tail columns of Q are ranked using
    /// Q's magnitude only — K/V cannot contribute past `k.cols - 1`.
    #[test]
    fn gqa_tail_columns_use_q_magnitude_only_when_kv_narrower() {
        let hidden = 8u32;
        let kv = 3u32;
        // Only Q column 7 carries signal; K,V are zero (narrow 4×3).
        let q = build_tensor(4, hidden, |_, c| if c == 7 { 10.0 } else { 0.0 });
        let k = build_tensor(4, kv, |_, _| 0.0);
        let v = build_tensor(4, kv, |_, _| 0.0);
        let manifest = manifest_from_weight_magnitudes(&q, &k, &v, 0.125);
        // coverage 0.125 of d=8 → k=1
        assert_eq!(manifest.k, 1);
        assert_eq!(
            manifest.standing_indices,
            vec![7],
            "tail column 7 must win when K/V are zero on the narrow prefix"
        );
    }

    /// Cloud probe `e839d9dd` motivation: a column that holds a single
    /// EXTREME-magnitude element (the ±72 / ±92 outliers seen in
    /// canonical L0 attn_q / ffn_gate fidelity) must survive manifest
    /// construction even when its column-L2 score is beaten by many
    /// denser-but-smaller columns.
    ///
    /// Setup: d=64, coverage=0.25 → k=16. Columns 0..15 each carry
    /// medium-magnitude values across every row (high L2 score).
    /// Column 32 has ONE extreme outlier (±72) and zeros elsewhere
    /// (low L2 score, but huge abs-max). Without the outlier-reserve
    /// pass, column 32 would be evicted by the dense columns.
    #[test]
    fn outlier_preservation_keeps_extreme_column() {
        let rows = 64u32;
        let d = 64u32;
        let outlier_col = 32u32;
        let outlier_value = 72.0f32;
        let dense_value = 0.5f32;

        let q = build_tensor(rows, d, |r, c| {
            if c < 16 {
                dense_value
            } else if c == outlier_col && r == 0 {
                outlier_value
            } else {
                0.0
            }
        });
        // K and V are zeros — the outlier lives in Q only, mirroring
        // the cloud-probe attn_q failure where the dropped element was
        // a single Q row position.
        let k = build_tensor(rows, d, |_, _| 0.0);
        let v = build_tensor(rows, d, |_, _| 0.0);

        let manifest = manifest_from_weight_magnitudes(&q, &k, &v, 0.25);
        assert_eq!(manifest.k, 16);
        assert!(
            manifest.standing_indices.contains(&outlier_col),
            "outlier column {} (abs-max={}) must survive manifest construction; got {:?}",
            outlier_col,
            outlier_value,
            manifest.standing_indices
        );
        // Indices are sorted ascending per the manifest contract.
        for w in manifest.standing_indices.windows(2) {
            assert!(
                w[0] < w[1],
                "indices must be sorted: {:?}",
                manifest.standing_indices
            );
        }
        assert!(manifest.is_well_formed());
    }

    /// The outlier reserve must not blow up the manifest size: with
    /// k=16 and at most `OUTLIER_RESERVE_FRACTION × 16 = 4` reserve
    /// slots, the union still has exactly 16 indices.
    #[test]
    fn outlier_preservation_respects_k_budget() {
        let rows = 32u32;
        let d = 64u32;
        // Many distinct outlier columns (32..48) with huge abs-max
        // values, plus dense columns 0..16 carrying L2 weight.
        let q = build_tensor(rows, d, |r, c| {
            if c < 16 {
                0.5
            } else if (32..48).contains(&c) && r == 0 {
                100.0
            } else {
                0.0
            }
        });
        let k = build_tensor(rows, d, |_, _| 0.0);
        let v = build_tensor(rows, d, |_, _| 0.0);
        // coverage 0.25 of d=64 → k=16
        let manifest = manifest_from_weight_magnitudes(&q, &k, &v, 0.25);
        assert_eq!(manifest.k, 16);
        assert_eq!(manifest.standing_indices.len(), 16);
    }

    /// Direct unit on the selector primitive: when score and abs_max
    /// disagree, the union should keep top-(k - reserve) score picks
    /// AND the top-reserve abs-max picks.
    #[test]
    fn select_with_outlier_reserve_unions_orderings() {
        // d=10, k=4. score favors {0,1,2,3}; abs_max favors {7,8,9}.
        // reserve = round(4 * 0.25) = 1, primary = 3.
        // Expected: {0,1,2} from score + {9} from abs_max → sorted [0,1,2,9].
        let score = vec![10.0, 9.0, 8.0, 7.0, 0.0, 0.0, 0.0, 0.5, 0.5, 0.5];
        let abs_max = vec![1.0, 1.0, 1.0, 1.0, 0.0, 0.0, 0.0, 50.0, 60.0, 70.0];
        let picks = select_with_outlier_reserve(10, 4, &score, &abs_max);
        assert_eq!(picks.len(), 4);
        assert_eq!(picks, vec![0, 1, 2, 9]);
    }

    /// GQA: large K/V energy on an early column can outrank a Q-only tail bump.
    #[test]
    fn gqa_kv_prefix_can_dominate_combined_score() {
        let hidden = 8u32;
        let kv = 3u32;
        let q = build_tensor(4, hidden, |_, c| if c == 7 { 5.0 } else { 0.01 });
        let k = build_tensor(4, kv, |_, c| if c == 0 { 20.0 } else { 0.0 });
        let v = build_tensor(4, kv, |_, c| if c == 0 { 20.0 } else { 0.0 });
        let manifest = manifest_from_weight_magnitudes(&q, &k, &v, 0.125);
        assert_eq!(manifest.k, 1);
        assert_eq!(
            manifest.standing_indices,
            vec![0],
            "column 0 should win from K+V contribution on the shared prefix"
        );
    }
}
